SELECT i.item_id , i.name , i.manufacturer , i.category_id as categoryId, i.color, i.price , i.stock , i.recommended , c.name AS categoryName FROM public.items i INNER JOIN public.categories c ON i.category_id = c.category_id
AND i.name LIKE CONCAT('%', #{keyword}, '%')
AND i.category_id = #{catedgoryId}

